const skill=document.querySelectorAll(".software .software__list-item--meter");skill.forEach(t=>{t.style.display="block";let e=isNaN(parseInt(t.dataset.skill,10))?"50%":100-parseInt(t.dataset.skill,10)+"%",l=document.createElement("span");l.setAttribute("style",`display: block;\nposition: absolute;\ntop: 0;\nright: 0;\nbottom: 0;\nleft: 0;\nbackground-image: linear-gradient(90deg, #f00, #ff0, #0f0);\nclip-path: inset(0 ${e} 0 0);`),t.appendChild(l)});